sort(
  1 / (
    avg by (provider) (
      (
        1 / avg by (provider, source_region) (
          quantile_over_time(0.95, 
            (response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success"} > 0)[$__range:$__interval]
          )
        )
      )
      *
      (
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{metric_type="response_time", blockchain="Solana"} > 0)[$__range:$__interval]))
        )
        *
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{metric_type="response_time", blockchain="Solana"} > 0)[$__range:$__interval]))
        )
        *
        (
          sum by (provider, source_region) (count_over_time((response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success"} > 0)[$__range:$__interval]))
          /
          sum by (provider, source_region) (count_over_time((response_latency_seconds{metric_type="response_time", blockchain="Solana"} > 0)[$__range:$__interval]))
        )
      )
    )
  )
)

